fn solve(s: String) -> i64 {
    let s = s.as_bytes();
    let n = s.len();
    let mut l_count = 0;
    let mut c_count = 0;
    let mut t_count = 0;
    let mut total = 0;

    // First pass: count the number of 'L's, 'C's after each 'L', and 'T's after each 'C'
    for &ch in s {
        match ch {
            b'L' => l_count += 1,
            b'C' => c_count += l_count,
            b'T' => total += c_count,
            _ => (),
        }
    }

    // Now, consider inserting each possible character (L, C, T) at every possible position
    let mut max_total = total;

    // Insert 'L' at position i (0..=n)
    let mut l_insert = 0;
    let mut current_l = 0;
    let mut current_c = 0;
    let mut current_t = 0;
    for i in 0..=n {
        // The contribution is (current_l + 1) * c_after_i + current_c
        let c_after = c_count_after(s, i);
        let t_after = t_count_after(s, i);
        let new_l = current_l + 1;
        let new_c = current_c + c_after;
        let new_t = current_t + t_after * new_l + new_c;
        if new_t > max_total {
            max_total = new_t;
        }
        if i < n {
            match s[i] {
                b'L' => current_l += 1,
                b'C' => current_c += current_l,
                b'T' => (),
                _ => (),
            }
        }
    }

    // Insert 'C' at position i (0..=n)
    let mut current_l = 0;
    let mut current_c = 0;
    let mut current_t = 0;
    for i in 0..=n {
        // The contribution is current_l * (c_after_i + 1) + current_c
        let c_after = c_count_after(s, i);
        let t_after = t_count_after(s, i);
        let new_l = current_l;
        let new_c = current_c + current_l; // for the inserted 'C'
        let new_c_total = new_c + c_after * new_l;
        let new_t = current_t + t_after * new_l + new_c_total;
        if new_t > max_total {
            max_total = new_t;
        }
        if i < n {
            match s[i] {
                b'L' => current_l += 1,
                b'C' => current_c += current_l,
                b'T' => (),
                _ => (),
            }
        }
    }

    // Insert 'T' at position i (0..=n)
    let mut current_l = 0;
    let mut current_c = 0;
    let mut current_t = 0;
    for i in 0..=n {
        // The contribution is current_l * c_after_i + current_c
        let c_after = c_count_after(s, i);
        let t_after = t_count_after(s, i);
        let new_l = current_l;
        let new_c = current_c;
        let new_t = current_t + (t_after + 1) * new_l + new_c;
        if new_t > max_total {
            max_total = new_t;
        }
        if i < n {
            match s[i] {
                b'L' => current_l += 1,
                b'C' => current_c += current_l,
                b'T' => (),
                _ => (),
            }
        }
    }

    max_total
}

fn c_count_after(s: &[u8], pos: usize) -> i64 {
    let mut count = 0;
    let mut l_count = 0;
    for &ch in s.iter().skip(pos) {
        match ch {
            b'L' => l_count += 1,
            b'C' => count += l_count,
            _ => (),
        }
    }
    count
}

fn t_count_after(s: &[u8], pos: usize) -> i64 {
    let mut count = 0;
    let mut c_count = 0;
    let mut l_count = 0;
    for &ch in s.iter().skip(pos) {
        match ch {
            b'L' => l_count += 1,
            b'C' => c_count += l_count,
            b'T' => count += c_count,
            _ => (),
        }
    }
    count
}
